+package auth
+
+import (
+	"context"
+	"encoding/json"
+	"fmt"
+	"net/http"
+	"net/url"
+	"os"
+	"strings"
+	"time"
+)
+
+// DeliverooAuthConfig holds configuration for Deliveroo authentication
+type DeliverooAuthConfig struct {
+	Market       string        `json:"market"`
+	BearerToken  string        `json:"bearer_token"`
+	RefreshToken string        `json:"refresh_token"`
+	ClientID     string        `json:"client_id"`
+	ClientSecret string        `json:"client_secret"`
+	AuthBaseURL  string        `json:"auth_base_url"`
+	TokenFile    string        `json:"token_file"`
+	AutoRefresh  bool          `json:"auto_refresh"`
+	HTTPTimeout  time.Duration `json:"http_timeout"`
+}
+
+// DeliverooAuthManager manages Deliveroo-specific authentication
+type DeliverooAuthManager struct {
+	*TokenManager
+	config DeliverooAuthConfig
+}
+
+// NewDeliverooAuthManager creates a new Deliveroo authentication manager
+func NewDeliverooAuthManager(config DeliverooAuthConfig) *DeliverooAuthManager {
+	// Set defaults
+	if config.HTTPTimeout == 0 {
+		config.HTTPTimeout = 15 * time.Second
+	}
+	if config.AuthBaseURL == "" {
+		config.AuthBaseURL = "https://co-m.uk.deliveroo.com"
+	}
+	if config.TokenFile == "" {
+		homeDir, _ := os.UserHomeDir()
+		config.TokenFile = homeDir + "/.delicli/tokens.json"
+	}
+
+	// Build refresh URL
+	refreshURL := config.AuthBaseURL + "/oauth2/token"
+
+	// Create token manager
+	tokenConfig := TokenManagerConfig{
+		RefreshURL:   refreshURL,
+		ClientID:     config.ClientID,
+		ClientSecret: config.ClientSecret,
+		InitialToken: config.BearerToken,
+		RefreshToken: config.RefreshToken,
+		HTTPTimeout:  config.HTTPTimeout,
+	}
+
+	return &DeliverooAuthManager{
+		TokenManager: NewTokenManager(tokenConfig),
+		config:       config,
+	}
+}
+
+// LoadFromEnvironment loads authentication config from environment variables
+func (dm *DeliverooAuthManager) LoadFromEnvironment() {
+	if market := os.Getenv("DELIVEROO_MARKET"); market != "" {
+		dm.config.Market = market
+	}
+	if token := os.Getenv("DELIVEROO_BEARER_TOKEN"); token != "" {
+		dm.config.BearerToken = token
+	}
+	if refreshToken := os.Getenv("DELIVEROO_REFRESH_TOKEN"); refreshToken != "" {
+		dm.config.RefreshToken = refreshToken
+	}
+	if clientID := os.Getenv("DELIVEROO_CLIENT_ID"); clientID != "" {
+		dm.config.ClientID = clientID
+	}
+	if clientSecret := os.Getenv("DELIVEROO_CLIENT_SECRET"); clientSecret != "" {
+		dm.config.ClientSecret = clientSecret
+	}
+}
+
+// SaveTokens saves current tokens to the configured token file
+func (dm *DeliverooAuthManager) SaveTokens() error {
+	// Ensure directory exists
+	dir := strings.TrimSuffix(dm.config.TokenFile, "/tokens.json")
+	if err := os.MkdirAll(dir, 0755); err != nil {
+		return fmt.Errorf("failed to create token directory: %w", err)
+	}
+	return dm.SaveToFile(dm.config.TokenFile)
+}
+
+// LoadTokens loads tokens from the configured token file
+func (dm *DeliverooAuthManager) LoadTokens() error {
+	if _, err := os.Stat(dm.config.TokenFile); os.IsNotExist(err) {
+		// File doesn't exist, try to load from environment first
+		dm.LoadFromEnvironment()
+
+		// If we have a bearer token from environment, use it
+		if dm.config.BearerToken != "" {
+			tokenInfo := &TokenInfo{
+				AccessToken: dm.config.BearerToken,
+				TokenType:   "Bearer",
+			}
+			if dm.config.RefreshToken != "" {
+				tokenInfo.RefreshToken = dm.config.RefreshToken
+			}
+			dm.SetToken(tokenInfo)
+			return nil
+		}
+
+		return fmt.Errorf("no token file found and no bearer token in environment")
+	}
+
+	// Load from file
+	if err := dm.LoadFromFile(dm.config.TokenFile); err != nil {
+		return err
+	}
+
+	// Still load environment to potentially override
+	dm.LoadFromEnvironment()
+
+	// If environment has bearer token, prioritize it
+	if dm.config.BearerToken != "" {
+		tm := dm.GetTokenInfo()
+		if tm == nil || tm.AccessToken != dm.config.BearerToken {
+			tokenInfo := &TokenInfo{
+				AccessToken:  dm.config.BearerToken,
+				RefreshToken: dm.config.RefreshToken,
+				TokenType:    "Bearer",
+			}
+			if tm != nil {
+				tokenInfo.ExpiresAt = tm.ExpiresAt
+			}
+			dm.SetToken(tokenInfo)
+		}
+	}
+
+	return nil
+}
+
+// AuthenticatedClient returns an HTTP client with Deliveroo authentication
+func (dm *DeliverooAuthManager) AuthenticatedClient() *http.Client {
+	interceptor := NewHTTPInterceptor(dm.TokenManager)
+	return interceptor.Client()
+}
+
+// MakeAuthenticatedRequest makes an authenticated HTTP request to Deliveroo APIs
+func (dm *DeliverooAuthManager) MakeAuthenticatedRequest(ctx context.Context, method, url string, headers http.Header) (*http.Response, error) {
+	client := dm.AuthenticatedClient()
+
+	req, err := http.NewRequestWithContext(ctx, method, url, nil)
+	if err != nil {
+		return nil, err
+	}
+
+	// Add custom headers
+	for key, values := range headers {
+		for _, value := range values {
+			req.Header.Add(key, value)
+		}
+	}
+
+	// Add market header if available
+	if dm.config.Market != "" {
+		req.Header.Set("X-Deliveroo-Market", dm.config.Market)
+	}
+
+	return client.Do(req)
+}
+
+// ValidateAuth checks if the current authentication is valid by making a test request
+func (dm *DeliverooAuthManager) ValidateAuth(ctx context.Context) error {
+	// Use a simple API endpoint to test auth
+	testURL := dm.config.AuthBaseURL + "/api/v1/user"
+
+	resp, err := dm.MakeAuthenticatedRequest(ctx, "GET", testURL, nil)
+	if err != nil {
+		return fmt.Errorf("failed to make auth validation request: %w", err)
+	}
+	defer resp.Body.Close()
+
+	if resp.StatusCode == http.StatusUnauthorized {
+		return fmt.Errorf("authentication failed - token may be expired")
+	}
+
+	if resp.StatusCode != http.StatusOK {
+		return fmt.Errorf("auth validation failed with status: %d", resp.StatusCode)
+	}
+
+	return nil
+}
+
+// Login performs the initial login flow using username/password or other credentials
+func (dm *DeliverooAuthManager) Login(ctx context.Context, loginURL, username, password string) error {
+	if dm.config.ClientID == "" || dm.config.ClientSecret == "" {
+		return fmt.Errorf("client ID and secret required for login")
+	}
+
+	// Create login form data
+	form := url.Values{}
+	form.Add("grant_type", "password")
+	form.Add("username", username)
+	form.Add("password", password)
+	form.Add("client_id", dm.config.ClientID)
+	form.Add("client_secret", dm.config.ClientSecret)
+
+	req, err := http.NewRequestWithContext(ctx, "POST", loginURL, strings.NewReader(form.Encode()))
+	if err != nil {
+		return err
+	}
+
+	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
+
+	client := &http.Client{Timeout: dm.config.HTTPTimeout}
+	resp, err := client.Do(req)
+	if err != nil {
+		return fmt.Errorf("login request failed: %w", err)
+	}
+	defer resp.Body.Close()
+
+	if resp.StatusCode != http.StatusOK {
+		return fmt.Errorf("login failed with status: %d", resp.StatusCode)
+	}
+
+	var tokenInfo TokenInfo
+	if err := json.NewDecoder(resp.Body).Decode(&tokenInfo); err != nil {
+		return fmt.Errorf("failed to decode login response: %w", err)
+	}
+
+	// Set expiry if provided
+	if tokenInfo.ExpiresIn > 0 {
+		tokenInfo.ExpiresAt = time.Now().Add(time.Duration(tokenInfo.ExpiresIn) * time.Second)
+	}
+
+	dm.SetToken(&tokenInfo)
+
+	// Save tokens for future use
+	if dm.config.TokenFile != "" {
+		if err := dm.SaveTokens(); err != nil {
+			// Log error but don't fail the login
+			fmt.Fprintf(os.Stderr, "Warning: failed to save tokens: %v\n", err)
+		}
+	}
+
+	return nil
+}
+
+// Logout clears authentication and removes saved tokens
+func (dm *DeliverooAuthManager) Logout() error {
+	dm.TokenManager.Logout()
+
+	if dm.config.TokenFile != "" {
+		if err := os.Remove(dm.config.TokenFile); err != nil && !os.IsNotExist(err) {
+			return fmt.Errorf("failed to remove token file: %w", err)
+		}
+	}
+
+	return nil
+}
+
+// GetAuthStatus returns current authentication status
+func (dm *DeliverooAuthManager) GetAuthStatus() map[string]any {
+	status := map[string]any{
+		"authenticated": dm.IsAuthorized(),
+		"market":        dm.config.Market,
+	}
+
+	if tokenInfo := dm.GetTokenInfo(); tokenInfo != nil {
+		status["token_type"] = tokenInfo.TokenType
+		status["expires_at"] = tokenInfo.ExpiresAt
+		status["has_refresh_token"] = tokenInfo.RefreshToken != ""
+		if !tokenInfo.ExpiresAt.IsZero() {
+			status["expires_in"] = time.Until(tokenInfo.ExpiresAt).String()
+		}
+	}
+
+	return status
+}

