+package auth
+
+import (
+	"context"
+	"encoding/json"
+	"fmt"
+	"net/http"
+	"os"
+	"sync"
+	"time"
+
+	"github.com/golang-jwt/jwt/v5"
+)
+
+// TokenInfo holds information about an authentication token
+type TokenInfo struct {
+	AccessToken  string    `json:"access_token"`
+	RefreshToken string    `json:"refresh_token,omitempty"`
+	TokenType    string    `json:"token_type"`
+	ExpiresAt    time.Time `json:"expires_at"`
+	ExpiresIn    int       `json:"expires_in,omitempty"`
+	Scope        string    `json:"scope,omitempty"`
+}
+
+// IsExpired checks if the token is expired or will expire within the buffer duration
+func (t *TokenInfo) IsExpired(buffer time.Duration) bool {
+	if t.ExpiresAt.IsZero() {
+		return false // If no expiry set, assume valid
+	}
+	return time.Now().After(t.ExpiresAt.Add(-buffer))
+}
+
+// JWTClaims represents the claims in a JWT token
+type JWTClaims struct {
+	UserID   string    `json:"user_id,omitempty"`
+	Email    string    `json:"email,omitempty"`
+	Market   string    `json:"market,omitempty"`
+	IssuedAt time.Time `json:"iat,omitempty"`
+	Expires  time.Time `json:"exp,omitempty"`
+	jwt.RegisteredClaims
+}
+
+// TokenManager manages authentication tokens with automatic refresh
+type TokenManager struct {
+	mu           sync.RWMutex
+	tokenInfo    *TokenInfo
+	refreshURL   string
+	clientID     string
+	clientSecret string
+	httpClient   *http.Client
+	tokenRefresh chan struct{}
+	stopRefresh  chan struct{}
+	expiryBuffer time.Duration
+}
+
+// TokenManagerConfig holds configuration for the token manager
+type TokenManagerConfig struct {
+	RefreshURL   string        `json:"refresh_url"`
+	ClientID     string        `json:"client_id"`
+	ClientSecret string        `json:"client_secret"`
+	InitialToken string        `json:"initial_token"`
+	RefreshToken string        `json:"refresh_token,omitempty"`
+	HTTPTimeout  time.Duration `json:"http_timeout"`
+	ExpiryBuffer time.Duration `json:"expiry_buffer"`
+}
+
+// NewTokenManager creates a new token manager
+func NewTokenManager(config TokenManagerConfig) *TokenManager {
+	if config.HTTPTimeout == 0 {
+		config.HTTPTimeout = 10 * time.Second
+	}
+	if config.ExpiryBuffer == 0 {
+		config.ExpiryBuffer = 5 * time.Minute
+	}
+
+	tm := &TokenManager{
+		refreshURL:   config.RefreshURL,
+		clientID:     config.ClientID,
+		clientSecret: config.ClientSecret,
+		httpClient:   &http.Client{Timeout: config.HTTPTimeout},
+		tokenRefresh: make(chan struct{}, 1),
+		stopRefresh:  make(chan struct{}),
+		expiryBuffer: config.ExpiryBuffer,
+	}
+
+	// Initialize with provided token
+	if config.InitialToken != "" {
+		tm.tokenInfo = &TokenInfo{
+			AccessToken:  config.InitialToken,
+			RefreshToken: config.RefreshToken,
+			TokenType:    "Bearer",
+		}
+
+		// Try to parse JWT to get expiry
+		if exp, err := tm.parseJWTExpiry(config.InitialToken); err == nil {
+			tm.tokenInfo.ExpiresAt = exp
+		}
+	}
+
+	return tm
+}
+
+// GetValidToken returns a valid access token, refreshing if necessary
+func (tm *TokenManager) GetValidToken(ctx context.Context) (string, error) {
+	tm.mu.RLock()
+	if tm.tokenInfo == nil {
+		tm.mu.RUnlock()
+		return "", fmt.Errorf("no token available")
+	}
+
+	// Check if token needs refresh
+	if !tm.tokenInfo.IsExpired(tm.expiryBuffer) {
+		token := tm.tokenInfo.AccessToken
+		tm.mu.RUnlock()
+		return token, nil
+	}
+	tm.mu.RUnlock()
+
+	// Need to refresh
+	if err := tm.refreshToken(ctx); err != nil {
+		return "", fmt.Errorf("failed to refresh token: %w", err)
+	}
+
+	tm.mu.RLock()
+	defer tm.mu.RUnlock()
+	if tm.tokenInfo == nil {
+		return "", fmt.Errorf("no token after refresh")
+	}
+	return tm.tokenInfo.AccessToken, nil
+}
+
+// refreshToken refreshes the access token using the refresh token
+func (tm *TokenManager) refreshToken(ctx context.Context) error {
+	tm.mu.Lock()
+	defer tm.mu.Unlock()
+
+	if tm.tokenInfo == nil || tm.tokenInfo.RefreshToken == "" {
+		return fmt.Errorf("no refresh token available")
+	}
+
+	// Create refresh request
+	req, err := http.NewRequestWithContext(ctx, "POST", tm.refreshURL, nil)
+	if err != nil {
+		return err
+	}
+
+	req.SetBasicAuth(tm.clientID, tm.clientSecret)
+	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
+
+	// Add form data
+	q := req.URL.Query()
+	q.Add("grant_type", "refresh_token")
+	q.Add("refresh_token", tm.tokenInfo.RefreshToken)
+	req.URL.RawQuery = q.Encode()
+
+	// Make request
+	resp, err := tm.httpClient.Do(req)
+	if err != nil {
+		return err
+	}
+	defer resp.Body.Close()
+
+	if resp.StatusCode != http.StatusOK {
+		return fmt.Errorf("token refresh failed with status: %d", resp.StatusCode)
+	}
+
+	var newToken TokenInfo
+	if err := json.NewDecoder(resp.Body).Decode(&newToken); err != nil {
+		return fmt.Errorf("failed to decode token response: %w", err)
+	}
+
+	// Update token info
+	newToken.RefreshToken = tm.tokenInfo.RefreshToken // Preserve refresh token if not returned
+	if newToken.ExpiresIn > 0 {
+		newToken.ExpiresAt = time.Now().Add(time.Duration(newToken.ExpiresIn) * time.Second)
+	} else {
+		// Try to parse JWT expiry
+		if exp, err := tm.parseJWTExpiry(newToken.AccessToken); err == nil {
+			newToken.ExpiresAt = exp
+		}
+	}
+
+	tm.tokenInfo = &newToken
+	return nil
+}
+
+// parseJWTExpiry extracts the expiry time from a JWT token
+func (tm *TokenManager) parseJWTExpiry(tokenString string) (time.Time, error) {
+	token, _, err := jwt.NewParser().ParseUnverified(tokenString, &JWTClaims{})
+	if err != nil {
+		return time.Time{}, err
+	}
+
+	claims, ok := token.Claims.(*JWTClaims)
+	if !ok {
+		return time.Time{}, fmt.Errorf("invalid token claims")
+	}
+
+	if claims.Expires.IsZero() {
+		return time.Time{}, fmt.Errorf("no expiry in token")
+	}
+
+	return claims.Expires, nil
+}
+
+// SetToken manually sets a new token
+func (tm *TokenManager) SetToken(tokenInfo *TokenInfo) {
+	tm.mu.Lock()
+	defer tm.mu.Unlock()
+	tm.tokenInfo = tokenInfo
+}
+
+// GetTokenInfo returns current token information
+func (tm *TokenManager) GetTokenInfo() *TokenInfo {
+	tm.mu.RLock()
+	defer tm.mu.RUnlock()
+	if tm.tokenInfo == nil {
+		return nil
+	}
+	// Return a copy
+	copy := *tm.tokenInfo
+	return &copy
+}
+
+// SaveToFile saves the current token to a file
+func (tm *TokenManager) SaveToFile(filename string) error {
+	tm.mu.RLock()
+	defer tm.mu.RUnlock()
+
+	if tm.tokenInfo == nil {
+		return fmt.Errorf("no token to save")
+	}
+
+	data, err := json.MarshalIndent(tm.tokenInfo, "", "  ")
+	if err != nil {
+		return err
+	}
+
+	return os.WriteFile(filename, data, 0600)
+}
+
+// LoadFromFile loads token from a file
+func (tm *TokenManager) LoadFromFile(filename string) error {
+	data, err := os.ReadFile(filename)
+	if err != nil {
+		return err
+	}
+
+	var tokenInfo TokenInfo
+	if err := json.Unmarshal(data, &tokenInfo); err != nil {
+		return err
+	}
+
+	tm.SetToken(&tokenInfo)
+	return nil
+}
+
+// IsAuthorized checks if we have a valid token
+func (tm *TokenManager) IsAuthorized() bool {
+	tm.mu.RLock()
+	defer tm.mu.RUnlock()
+	return tm.tokenInfo != nil && !tm.tokenInfo.IsExpired(tm.expiryBuffer)
+}
+
+// Logout clears the stored tokens
+func (tm *TokenManager) Logout() {
+	tm.mu.Lock()
+	defer tm.mu.Unlock()
+	tm.tokenInfo = nil
+}
+
+// HTTPInterceptor creates an HTTP transport that adds authentication headers
+type HTTPInterceptor struct {
+	tokenManager *TokenManager
+	transport    http.RoundTripper
+}
+
+// NewHTTPInterceptor creates a new HTTP interceptor
+func NewHTTPInterceptor(tm *TokenManager) *HTTPInterceptor {
+	return &HTTPInterceptor{
+		tokenManager: tm,
+		transport:    http.DefaultTransport,
+	}
+}
+
+// RoundTrip implements http.RoundTripper
+func (i *HTTPInterceptor) RoundTrip(req *http.Request) (*http.Response, error) {
+	ctx := req.Context()
+
+	// Get valid token
+	token, err := i.tokenManager.GetValidToken(ctx)
+	if err != nil {
+		return nil, fmt.Errorf("failed to get auth token: %w", err)
+	}
+
+	// Clone request to avoid modifying original
+	req = req.Clone(ctx)
+	req.Header.Set("Authorization", "Bearer "+token)
+
+	// Make the request
+	return i.transport.RoundTrip(req)
+}
+
+// Client creates an HTTP client with authentication interceptors
+func (i *HTTPInterceptor) Client() *http.Client {
+	return &http.Client{
+		Transport: i,
+		Timeout:   10 * time.Second,
+	}
+}

