+// parseOrderStatus parses order data from API response
+func (oc *OrderChecker) parseOrderStatus(data map[string]any) (*OrderStatus, error) {
+	order := &OrderStatus{
+		Metadata: make(map[string]string),
+	}
+
+	// Parse basic fields
+	if id, ok := data["id"].(string); ok {
+		order.OrderID = id
+	}
+	if id, ok := data["order_id"].(string); ok {
+		order.OrderID = id
