+		}
+	}
+	if eta, ok := data["eta"].(string); ok {
+		order.ETA = eta
+	}
+	if total, ok := data["total_amount"].(string); ok {
+		order.TotalAmount = total
+	}
+	if currency, ok := data["currency"].(string); ok {
+		order.Currency = currency
+	}
+
+	// Parse timestamps
+	if updatedAt, ok := data["updated_at"].(string); ok {
+		if t, err := time.Parse(time.RFC3339, updatedAt); err == nil {
+			order.UpdatedAt = t
+		}
+	}
+
+	// Parse items
+	if items, ok := data["items"].([]any); ok {
+		for _, item := range items {
+			if itemData, ok := item.(map[string]any); ok {
