+			}
+		}
+	}
+
+	// Parse events
+	if events, ok := data["events"].([]any); ok {
+		for _, event := range events {
+			if eventData, ok := event.(map[string]any); ok {
+				orderEvent := OrderEvent{}
+				if message, ok := eventData["message"].(string); ok {
+					orderEvent.Message = message
+				}
+				if eventType, ok := eventData["type"].(string); ok {
+					orderEvent.Type = eventType
+				}
+				if timestamp, ok := eventData["time"].(string); ok {
