+	// Parse delivery info
+	if delivery, ok := data["delivery"].(map[string]any); ok {
+		order.DeliveryInfo = &DeliveryInfo{}
+		if address, ok := delivery["address"].(string); ok {
+			order.DeliveryInfo.DeliveryAddress = address
+		}
+		if driver, ok := delivery["driver"].(map[string]any); ok {
+			if name, ok := driver["name"].(string); ok {
+				order.DeliveryInfo.DriverName = name
+			}
+			if phone, ok := driver["phone"].(string); ok {
