+
+// FormatDetailed creates a detailed format of the order status
+func (order *OrderStatus) FormatDetailed() string {
+	var builder strings.Builder
+
+	builder.WriteString(fmt.Sprintf("Order: %s\n", order.OrderID))
+	builder.WriteString(fmt.Sprintf("Status: %s\n", order.Status))
+	builder.WriteString(fmt.Sprintf("Restaurant: %s\n", order.Restaurant))
