+
+	if !order.UpdatedAt.IsZero() {
+		builder.WriteString(fmt.Sprintf("Updated: %s\n", order.UpdatedAt.Format(time.RFC3339)))
+	}
+
+	if len(order.Items) > 0 {
+		builder.WriteString("\nItems:\n")
+		for _, item := range order.Items {
+			builder.WriteString(fmt.Sprintf("  - %s x%d (%s)", item.Name, item.Quantity, item.Price))
+			if item.Category != "" {
+				builder.WriteString(fmt.Sprintf(" [%s]", item.Category))
