+package source
+
+import (
+	"context"
+	"fmt"
+	"os"
+)
+
+type fileSource struct {
+	path string
+}
+
+func NewFile(path string) BytesSource {
+	return &fileSource{path: path}
+}
+
+func (f *fileSource) String() string { return "file:" + f.path }
+
+func (f *fileSource) Fetch(_ context.Context) ([]byte, error) {
+	b, err := os.ReadFile(f.path)
+	if err != nil {
+		return nil, fmt.Errorf("read %s: %w", f.path, err)
+	}
+	return lastJSONFromMaybeJSONL(b)
+}
+
+func lastJSONFromMaybeJSONL(b []byte) ([]byte, error) {
+	tb := trimSpace(b)
+	if len(tb) == 0 {
+		return nil, fmt.Errorf("empty file")
+	}
+
+	lines := splitLines(b)
+	if looksLikeJSONLines(lines) {
+		for i := len(lines) - 1; i >= 0; i-- {
+			line := trimSpace(lines[i])
+			if len(line) == 0 {
+				continue
+			}
+			return line, nil
+		}
+		return nil, fmt.Errorf("empty file")
+	}
+
+	// Otherwise, treat as a single JSON document.
+	if tb[0] == '{' || tb[0] == '[' {
+		return tb, nil
+	}
+
+	// Fallback: take the last non-empty line that looks like JSON.
+	for i := len(lines) - 1; i >= 0; i-- {
+		line := trimSpace(lines[i])
+		if len(line) == 0 {
+			continue
+		}
+		if line[0] != '{' && line[0] != '[' {
+			continue
+		}
+		return line, nil
+	}
+	return nil, fmt.Errorf("no json object found")
+}
+
+func looksLikeJSONLines(lines [][]byte) bool {
+	nonEmpty := 0
+	ok := 0
+	for _, ln := range lines {
+		t := trimSpace(ln)
+		if len(t) == 0 {
+			continue
+		}
+		nonEmpty++
+		if (t[0] == '{' && t[len(t)-1] == '}') || (t[0] == '[' && t[len(t)-1] == ']') {
+			ok++
+			continue
+		}
+		return false
+	}
+	return nonEmpty > 1 && ok == nonEmpty
+}
+
+func trimSpace(b []byte) []byte {
+	for len(b) > 0 {
+		switch b[0] {
+		case ' ', '\t', '\n', '\r':
+			b = b[1:]
+		default:
+			goto endStart
+		}
+	}
+endStart:
+	for len(b) > 0 {
+		switch b[len(b)-1] {
+		case ' ', '\t', '\n', '\r':
+			b = b[:len(b)-1]
+		default:
+			return b
+		}
+	}
+	return b
+}
+
+func splitLines(b []byte) [][]byte {
+	var out [][]byte
+	start := 0
+	for i := 0; i < len(b); i++ {
+		if b[i] == '\n' {
+			out = append(out, b[start:i])
+			start = i + 1
+		}
+	}
+	out = append(out, b[start:])
+	return out
+}

