+package watch
+
+import (
+	"context"
+	"crypto/sha256"
+	"encoding/hex"
+	"time"
+
+	"delicli/internal/source"
+)
+
+type Update[T any] struct {
+	Value T
+	Err   error
+}
+
+type UnmarshalFunc[T any] func([]byte) (T, error)
+
+func Poll[T any](ctx context.Context, bs source.BytesSource, interval time.Duration, unmarshal UnmarshalFunc[T]) <-chan Update[T] {
+	out := make(chan Update[T])
+
+	go func() {
+		defer close(out)
+
+		var lastHash string
+		ticker := time.NewTicker(interval)
+		defer ticker.Stop()
+
+		send := func() bool {
+			b, err := bs.Fetch(ctx)
+			if err != nil {
+				select {
+				case out <- Update[T]{Err: err}:
+					return true
+				case <-ctx.Done():
+					return false
+				}
+			}
+
+			sum := sha256.Sum256(b)
+			hash := hex.EncodeToString(sum[:])
+			if hash == lastHash {
+				return true
+			}
+			lastHash = hash
+
+			v, err := unmarshal(b)
+			select {
+			case out <- Update[T]{Value: v, Err: err}:
+				return true
+			case <-ctx.Done():
+				return false
+			}
+		}
+
+		if !send() {
+			return
+		}
+
+		for {
+			select {
+			case <-ctx.Done():
+				return
+			case <-ticker.C:
+				if !send() {
+					return
+				}
+			}
+		}
+	}()
+
+	return out
+}
